  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — wall-stun him on the Heroic Swing cooldown and All Out the 1v1.","breakdown":"Akshan plays around Heroic Swing. Chain Q slows into the Q3 knockup when Heroic Swing is down, W-tank the answer, and R him into a wall for the All Out duel. Doran’s Shield blunts the poke war.","dos":["Stack Q on the wave","Q3-knockup when Heroic Swing is down","All Out the committed duel"],"donts":["Burn W charge into nothing","Eat his Heroic Swing mid-Q3","All Out into his peel"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Q3-knockup, All Out the duel."},"win":"Wall-stun him on the Heroic Swing cooldown and All Out the 1v1."},
